def hybrid_posterior(
    vec_a: List[float],
    vec_b: List[float],
    start_year: int = 2000,
    end_year: int = 2020,
) -> np.ndarray:
    """
    Compute the posterior distribution over weekdays by fusing:
    * Doomsday prior (Parent B)
    * Pheromone‑entropy likelihood (Parent B)
    * Fisher‑weighted SSIM likelihood from feature vectors (Parent A)
    """
    # 1️⃣ Doomsday prior
    counts = weekday_counts(start_year, end_year)
    prior = normalize(counts)                     # π_i

    # 2️⃣ Pheromone evidence → likelihood L_i
    pher_evidence, entropy = pheromone_evidence(prior)
    L_pher = np.exp(-entropy) * pher_evidence      # shape (7,)

    # 3️⃣ Feature similarity → single scalar likelihood ℓ
    feature_likelihood = fisher_weighted_similarity(vec_a, vec_b)  # ∈ [0,1] approx
    L_feat = np.full_like(prior, feature_likelihood)               # broadcast

    # 4️⃣ Combine all likelihood components (element‑wise product)
    combined_likelihood = L_pher * L_feat

    # 5️⃣ Bayesian update
    posterior = bayes_update(prior, combined_likelihood)
    return posterior


def dispersion_metric(start_year: int = 2000, end_year: int = 2020) -> float:
    """
    Compute a unified dispersion metric Δ that blends:
    * Gini coefficient of Doomsday weekday frequencies
    * Normalised Shannon entropy of pheromone evidence
    """
    counts = weekday_counts(start_year, end_year)
    freq_vals = list(counts.values())
    gini = gini_coefficient(freq_vals)

    prior = normalize(counts)
    _, entropy = pheromone_evidence(prior)
    # Normalise entropy to [0,1] (max entropy = ln(7))
    H_norm = entropy / math.log(7)

    return math.sqrt(gini * gini + H_norm * H_norm)


def mst_weighted_cost(
    points: List[Tuple[float, float]],
    posterior: np.ndarray,
) -> float:
    """
    Build a Euclidean minimum‑cost spanning tree where each node i
    (corresponding to weekday i) carries weight w_i = posterior_i.
    Edge cost = Euclidean distance * (w_i + w_j)/2.
    Returns total weighted cost.
    """
    n = len(points)
    if n != 7:
        raise ValueError("Exactly 7 points (one per weekday) required.")
    # Compute all edges
    edges = []
    for i in range(n):
        for j in range(i + 1, n):
            xi, yi = points[i]
            xj, yj = points[j]
            dist = math.hypot(xi - xj, yi - yj)
            weight = (posterior[i] + posterior[j]) / 2.0
            edges.append((dist * weight, i, j))

    # Kruskal's algorithm
    parent = list(range(n))

    def find(u):
        while parent[u] != u:
            parent[u] = parent[parent[u]]
            u = parent[u]
        return u

    def union(u, v):
        ru, rv = find(u), find(v)
        if ru != rv:
            parent[rv] = ru
            return True
        return False

    edges.sort(key=lambda e: e[0])
    total_cost = 0.0
    for cost, i, j in edges:
        if union(i, j):
            total_cost += cost
            if sum(1 for k in range(n) if find(k) == find(0)) == n:
                break
    return total_cost


